// Mirrors React-template Blockquote.jsx — blockquote-style-01, 02

interface Props {
  theme?: "blockquote-style-01" | "blockquote-style-02" | "blockquote-style-03" | "blockquote-style-04" | "blockquote-style-05";
  quote: string;
  author?: string;
}

export default function Blockquote({ theme = "blockquote-style-01", quote, author }: Props) {
  if (theme === "blockquote-style-02") {
    return (
      <div className="blockquote-02">
        <blockquote>{quote}</blockquote>
        {author && (
          <>
            <div className="bq-sep" />
            <span className="bq-author">{author}</span>
          </>
        )}
      </div>
    );
  }

  if (theme === "blockquote-style-03") {
    return (
      <div className="blockquote-03">
        <div className="bq-icon">"</div>
        <p>{quote}</p>
        {author && <div className="bq-author">— {author}</div>}
      </div>
    );
  }
  if (theme === "blockquote-style-04") {
    return (
      <div className="blockquote-04">
        <div className="bq-icon">"</div>
        <p>{quote}</p>
        {author && <div className="bq-author">— {author}</div>}
      </div>
    );
  }
  if (theme === "blockquote-style-05") {
    return (
      <div className="blockquote-05">
        <div className="bq-icon">"</div>
        <p>{quote}</p>
        {author && <div className="bq-author">— {author}</div>}
      </div>
    );
  }

  return (
    <div className="blockquote-01">
      <span className="bq-icon">"</span>
      <blockquote>{quote}</blockquote>
      {author && <span className="bq-author">— {author}</span>}
    </div>
  );
}
