// Mirrors React-template IconWithText.jsx — icon-with-text-01 to 05
// Usage: <IconWithText theme="icon-with-text-01" data={...} grid="grid-cols-2" />

import type { ReactNode } from "react";

export interface IWTItem {
  icon?: ReactNode;
  number?: string;
  title: string;
  content: string;
  link?: string;
}

interface Props {
  theme: "icon-with-text-01" | "icon-with-text-02" | "icon-with-text-03" | "icon-with-text-04" | "icon-with-text-05" | "icon-with-text-06" | "icon-with-text-07" | "icon-with-text-08" | "icon-with-text-09" | "icon-with-text-10" | "icon-with-text-11";
  data: IWTItem[];
  grid?: string;
}

export default function IconWithText({ theme, data, grid = "grid-cols-1" }: Props) {
  return (
    <div className={`grid ${grid} gap-6`}>
      {data.map((item, i) => {
        if (theme === "icon-with-text-01") return <Style01 key={i} item={item} />;
        if (theme === "icon-with-text-02") return <Style02 key={i} item={item} />;
        if (theme === "icon-with-text-03") return <Style03 key={i} item={item} />;
        if (theme === "icon-with-text-04") return <Style04 key={i} item={item} />;
        if (theme === "icon-with-text-05") return <Style05 key={i} item={item} />;
        if (theme === "icon-with-text-06") return <Style06 key={i} item={item} />;
        if (theme === "icon-with-text-07") return <Style07 key={i} item={item} num={String(i + 1).padStart(2, "0")} />;
        if (theme === "icon-with-text-08") return <Style08 key={i} item={item} />;
        if (theme === "icon-with-text-09") return <Style09 key={i} item={item} />;
        if (theme === "icon-with-text-10") return <Style10 key={i} item={item} />;
        if (theme === "icon-with-text-11") return <Style11 key={i} item={item} />;
        return null;
      })}
    </div>
  );
}

function Style01({ item }: { item: IWTItem }) {
  return (
    <div className="iwt-01">
      <div className="iwt-icon">{item.icon || "★"}</div>
      <div>
        <h5>{item.title}</h5>
        <p>{item.content}</p>
      </div>
    </div>
  );
}

