// Mirrors React-template ProcessStep.jsx — process-step-style-01 to 04

import type { ReactNode } from "react";

export interface StepItem {
  icon?: ReactNode;
  title: string;
  content: string;
}

interface Props {
  theme?: "process-step-style-01" | "process-step-style-02" | "process-step-style-03" | "process-step-style-04" | "process-step-style-05" | "process-step-style-06";
  data: StepItem[];
  grid?: string;
}

export default function ProcessStep({ theme = "process-step-style-01", data, grid }: Props) {
  if (theme === "process-step-style-05") {
    return (
      <div className="ps-05-row">
        {data.map((item, i) => (
          <div key={i} className="ps-05">
            <div className="ps-number">{String(i + 1).padStart(2, "0")}</div>
            <h6>{item.title}</h6>
            <p>{item.content}</p>
          </div>
        ))}
      </div>
    );
  }

  if (theme === "process-step-style-06") {
    return (
      <div className="ps-06-wrap">
        {data.map((item, i) => (
          <>
            <div key={i} className="ps-06">
              <div className="ps-number">{String(i + 1).padStart(2, "0")}</div>
              <div>
                <h6>{item.title}</h6>
                <p>{item.content}</p>
              </div>
            </div>
            {i < data.length - 1 && <div className="ps-06-connector">→</div>}
          </>
        ))}
      </div>
    );
  }

  if (theme === "process-step-style-03") {
    return (
      <div className="ps-03-wrap overflow-x-auto">
        {data.map((item, i) => (
          <div key={i} className="ps-03 px-4">
            <div className="ps-icon-wrap">{item.icon || "★"}</div>
            <h5>{item.title}</h5>
            <p>{item.content}</p>
          </div>
        ))}
      </div>
    );
  }

  const defaultGrid =
    theme === "process-step-style-01"
      ? "grid-cols-1 sm:grid-cols-2 lg:grid-cols-4"
      : theme === "process-step-style-04"
      ? "grid-cols-1"
      : "grid-cols-1 sm:grid-cols-2";

  return (
    <div className={`grid ${grid ?? defaultGrid} gap-6`}>
      {data.map((item, i) => {
        const num = String(i + 1).padStart(2, "0");
        if (theme === "process-step-style-01") return <Style01 key={i} item={item} />;
        if (theme === "process-step-style-02") return <Style02 key={i} item={item} num={num} />;
        if (theme === "process-step-style-04") return <Style04 key={i} item={item} num={num} />;
        return null;
      })}
    </div>
  );
}

function Style01({ item }: { item: StepItem }) {
  return (
    <div className="ps-01">
      <div className="ps-icon">{item.icon || "💡"}</div>
      <h5>{item.title}</h5>
      <p>{item.content}</p>
    </div>
  );
}

function Style02({ item, num }: { item: StepItem; num: string }) {
  return (
    <div className="ps-02">
      <div className="ps-num">{num}</div>
      <div>
        <h5>{item.title}</h5>
        <p>{item.content}</p>
      </div>
    </div>
  );
}

function Style04({ item, num }: { item: StepItem; num: string }) {
  return (
    <div className="ps-04">
      <div className="ps-num">{num}</div>
      <div>
        <h5>{item.title}</h5>
        <p>{item.content}</p>
      </div>
    </div>
  );
}
